MERGE INTO CONSULTAS FIN USING (SELECT '002476Ayudaprocesos' INFORME ,TO_CLOB(q'[SELECT AYUDA_PROCESOS.ID_PROCESO, AYUDA_PROCESOS.NOMBRE NOMBRE_PROCESO, AYUDA_PROCESOS.APLICACION, APLICACIONES.NOMBRE NOMBRE_APLICACION, 
AYUDA_TAREAS.ORDEN, CASE WHEN AYUDA_TAREAS.TIPO = 'P' THEN 'PRERREQUISITOS' ELSE 'VALIDACIÓN' END DES_TIPO,
AYUDA_TAREAS.ID_TAREA, AYUDA_TAREAS.TIPO, AYUDA_TAREAS.DESCRIPCION, AYUDA_TAREAS.FORMULARIO, AYUDA_TAREAS.CONTROL, AYUDA_TAREAS.URL_VIDEO,
AYUDA_TAREAS.OTROS_RECURSOS, AYUDA_TAREAS.RUTA, AYUDA_TAREAS.TENERCUENTA
FROM AYUDA_PROCESOS
INNER JOIN AYUDA_TAREAS
ON AYUDA_PROCESOS.ID_PROCESO = AYUDA_TAREAS.ID_PROCESO
INNER JOIN APLICACIONES
ON AYUDA_PROCESOS.APLICACION = APLICACIONES.APLICACION
WHERE AYUDA_PROCESOS.ID_PROCESO = s$proceso$s
ORDER BY AYUDA_TAREAS.TIPO, AYUDA_TAREAS.ORDEN]') CONSULTA, 6 APLICACION ,TO_CLOB(q'[]') CONSULTA_OPCIONAL, NULL CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (INI.INFORME = FIN.INFORME )  WHEN MATCHED THEN  UPDATE SET FIN.CONSULTA =  INI.CONSULTA, FIN.APLICACION =  INI.APLICACION, FIN.CONSULTA_OPCIONAL =  INI.CONSULTA_OPCIONAL, FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME,CONSULTA, APLICACION,CONSULTA_OPCIONAL,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME,INI.CONSULTA, INI.APLICACION,INI.CONSULTA_OPCIONAL,INI.CREATED_BY,SYSDATE);